import { H4 } from "../../../AbstractElements";

export const AccountColumns = (authState) => [
        {
            name: <H4>Name</H4>,
            selector: row => row.Name,
            sortable: true,
            width: '170px',
            wrap: true
        },
        {
            name: <H4>Account No.</H4>,
            selector: row => row.Number,
            sortable: true,
            width: '130px',
            wrap: true,
        },
        {
            name: <H4>Opening Balance</H4>,
            selector: row => parseFloat(
                row.Balance
                    .replace(authState.currency, '')
                    .replace(/,/g, '')
                    .trim()
            ),
            cell: row => row.Balance,
            sortable: true,
            width: '150px',
            center: true
        },
        {
            name: <H4>Current Balance</H4>,
            selector: row => parseFloat(
                row.Current_balance
                    .replace(authState.currency, '')
                    .replace(/,/g, '')
                    .trim()
            ),
            cell: row => row.Current_balance,
            sortable: true,
            width: '150px',
            center: true
        },
        {
            name: <H4>Show On Invoice</H4>,
            selector: row => row.DefStatus,
            sortable: true,
            center: true
        },
        {
            name: <H4>Status</H4>,
            selector: row => row.Status,
            sortable: true,
            width: '150px',
            center: true
        },
        {
            name: <H4>Action</H4>,
            selector: row => row.action,
            sortable: true,
            center: true
        },
    ];